import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"XiHan.Framework.AI.Abstractions","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/ai-abstractions.md","filePath":"cosmos/framework/packages/ai-abstractions.md","lastUpdated":1783216089000}'),d={name:"cosmos/framework/packages/ai-abstractions.md"};function i(n,e,c,s,l,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="xihan-framework-ai-abstractions" tabindex="-1">XiHan.Framework.AI.Abstractions <a class="header-anchor" href="#xihan-framework-ai-abstractions" aria-label="Permalink to &quot;XiHan.Framework.AI.Abstractions&quot;">​</a></h1><blockquote><p>AI 抽象：AI 服务接口与契约</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.AI.Abstractions</code></li><li><strong>模块类</strong>：<code>—（无模块类，直接引用）</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>这个包只放 AI 相关的接口与契约，不含任何具体实现。它把「会话、Agent、多 provider 选择、提示词库、RAG（检索增强生成）」抽成一组接口，让上层代码只依赖抽象；真正的实现由 <code>XiHan.Framework.AI</code> 提供，应用层（如把 provider 配置存进数据库）也能通过实现这些接口来替换默认行为。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>你的库/模块需要引用 AI 会话或 RAG 契约，但不想拉入具体实现与第三方 SDK</li><li>你要提供自定义的 provider 配置源、提示词库或向量检索实现，替换框架默认项</li><li>想以 provider 名解耦模型调用，而不把某个厂商写死在业务里</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.AI.Abstractions</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><p>无模块类。直接引用即可，无需 <code>[DependsOn]</code>；具体实现与服务注册由 <code>XiHan.Framework.AI</code> 的 <code>XiHanAIModule</code> 负责。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>会话门面契约</strong>：<code>IXiHanAiService</code> 定义一次对话 / 流式对话，薄封装 <code>Microsoft.Extensions.AI</code> 的 <code>IChatClient</code>，只加「多 provider 选择」这层语义</li><li><strong>多 provider 解析</strong>：<code>IAiChatClientResolver</code> / <code>IAiEmbeddingGeneratorResolver</code> 按 provider 名取已构建好的会话客户端 / 嵌入生成器，并支持 <code>Invalidate</code> 配置热切换</li><li><strong>可插拔配置源</strong>：<code>IAiProviderConfigStore</code> 抽象 provider 配置来源（默认读 Options，应用层可换 DB store），配置载体是 <code>AiProviderOptions</code></li><li><strong>Agent 与技能</strong>：<code>IXiHanAgentFactory</code> 基于 Microsoft Agent Framework 构建 <code>AIAgent</code>；<code>IAiSkill</code> / <code>IAiSkillRegistry</code> 把应用注册的命名能力暴露为对话工具与 MCP tool</li><li><strong>RAG 契约</strong>：<code>IChunkingStrategy</code>（切片）、<code>IKnowledgeIngestor</code>（摄取）、<code>IKnowledgeRetriever</code>（检索）、<code>IRagPromptAugmenter</code>（提示增强）</li><li><strong>提示词库</strong>：<code>IAiPromptStore</code> / <code>AiPromptTemplate</code> 抽象可版本化的提示模板来源</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>IXiHanAiService</code></td><td>AI 会话服务门面（一次对话 / 流式对话）</td></tr><tr><td><code>IAiChatClientResolver</code></td><td>按 provider 名解析 <code>IChatClient</code>，含 <code>Invalidate</code> 热切换</td></tr><tr><td><code>IAiEmbeddingGeneratorResolver</code></td><td>按 provider 名解析嵌入生成器（RAG 用）</td></tr><tr><td><code>IAiProviderConfigStore</code></td><td>provider 配置来源抽象（Options 兜底 / 应用层可换 DB）</td></tr><tr><td><code>AiProviderOptions</code></td><td>单个 provider 配置：密钥 / 端点 / 会话模型 / 嵌入模型 / 采样</td></tr><tr><td><code>IXiHanAgentFactory</code></td><td>从 provider 解析器构建 Microsoft Agent Framework 的 <code>AIAgent</code></td></tr><tr><td><code>IAiSkill</code> / <code>IAiSkillRegistry</code></td><td>命名 AI 技能与注册表（暴露为对话工具 / MCP tool）</td></tr><tr><td><code>IKnowledgeIngestor</code> / <code>IKnowledgeRetriever</code></td><td>RAG 摄取与检索契约</td></tr><tr><td><code>IChunkingStrategy</code> / <code>IRagPromptAugmenter</code></td><td>文本切片策略 / 检索片段注入提示</td></tr><tr><td><code>IAiPromptStore</code> / <code>AiPromptTemplate</code></td><td>提示词库抽象与模板</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>无框架内部依赖（不引用任何 <code>XiHan.Framework.*</code>）</li><li>第三方核心：<strong>Microsoft.Extensions.AI.Abstractions</strong>（<code>IChatClient</code> / <code>IEmbeddingGenerator</code>）+ <strong>Microsoft.Agents.AI.Abstractions</strong>（Agent 抽象）</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./ai">XiHan.Framework.AI</a>（这些抽象的默认实现）</li></ul>',19)])])}const A=o(d,[["render",i]]);export{p as __pageData,A as default};
